import React, { useState, useEffect } from 'react';
import Logo from './Logo.png'; 
import Menu, { Lunch } from './Menu'; 

const gold = '#D4AF37'; 
const terracotta = '#C04000'; // Rich Earthy Clay
const clayLight = '#E2725B'; // Lighter Terracotta
const softCream = '#FDF5E6'; // Off-white for text/buttons

const WigStore = () => {
  const categories = [
    { type: "Human Hair", items: [{ name: "Raw Cambodian", price: "85,000" }] },
    { type: "Premium Fibre", items: [{ name: "Sleek Straight", price: "35,000" }] },
    { type: "Hair Blend", items: [{ name: "Piano Wavy", price: "25,000" }] }
  ];

  return (
    <div style={{ padding: '0 15px' }}>
      {categories.map((cat) => (
        <div key={cat.type} style={{ marginBottom: '10px' }}>
          <h3 style={{ fontSize: '0.65rem', color: terracotta, textTransform: 'uppercase', letterSpacing: '1.5px', marginBottom: '5px' }}>{cat.type}</h3>
          {cat.items.map((item) => (
            <div key={item.name} style={{ display: 'flex', backgroundColor: '#111', borderRadius: '8px', marginBottom: '6px', padding: '8px', alignItems: 'center' }}>
              <div style={{ width: '45px', height: '45px', backgroundColor: '#000', borderRadius: '4px', marginRight: '10px' }}></div>
              <div style={{ flex: 1 }}>
                <h4 style={{ fontSize: '0.75rem', margin: '0', color: '#fff' }}>{item.name}</h4>
                <div style={{ fontSize: '0.8rem', fontWeight: 'bold', color: gold }}>₦{item.price}</div>
              </div>
              <button style={{ backgroundColor: terracotta, color: '#fff', border: 'none', borderRadius: '12px', padding: '3px 10px', fontSize: '0.6rem' }}>ADD</button>
            </div>
          ))}
        </div>
      ))}
    </div>
  );
};

function App() {
  const [activeCategory, setActiveCategory] = useState('Small Chops');
  const [currentSlide, setCurrentSlide] = useState(0);

  const slides = [
    { title: "SMALL CHOPS", subtitle: "Handcrafted flavor." },
    { title: "THE HAIR EDIT", subtitle: "Unmatched quality." },
    { title: "OFFICE LUNCH", subtitle: "Gourmet corporate meals." }
  ];

  useEffect(() => {
    const timer = setInterval(() => setCurrentSlide((s) => (s + 1) % slides.length), 4000);
    return () => clearInterval(timer);
  }, []);

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', fontFamily: 'system-ui, sans-serif' }}>
      
      {/* 1. BRAND HEADER - Logo visibility fix */}
      <header style={{ 
        padding: '8px 15px', 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center', 
        position: 'sticky', 
        top: 0, 
        backgroundColor: '#000', 
        zIndex: 100 
      }}>
        <div style={{ backgroundColor: '#fff', borderRadius: '50%', padding: '5px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <img src={Logo} alt="Logo" style={{ height: '28px', width: '28px', objectFit: 'contain' }} />
        </div>
        <div style={{ display: 'flex', gap: '15px', fontSize: '1.1rem' }}>👤 🛒</div>
      </header>

      {/* 2. TERRACOTTA HERO - No Black, No Shimmer */}
      <div style={{ 
        width: '100%', 
        height: '130px', // Shrinking height to pull content up
        position: 'relative', 
        overflow: 'hidden', 
        background: `linear-gradient(135deg, ${terracotta} 0%, ${clayLight} 100%)` 
      }}>
        {slides.map((slide, index) => (
          <div key={index} style={{
            position: 'absolute', top: 0, left: 0, width: '100%', height: '100%',
            opacity: index === currentSlide ? 1 : 0,
            transition: 'opacity 1s ease-in-out',
            display: 'flex', flexDirection: 'column', justifyContent: 'center', padding: '0 20px'
          }}>
            <h2 style={{ fontSize: '1.1rem', color: '#fff', fontWeight: '800', margin: 0, letterSpacing: '1px' }}>{slide.title}</h2>
            <p style={{ fontSize: '0.7rem', color: softCream, margin: 0, opacity: 0.9 }}>{slide.subtitle}</p>
          </div>
        ))}
      </div>

      {/* 3. TIGHTENED INFO BLOCK */}
      <div style={{ padding: '10px 20px 5px' }}>
        <h1 style={{ fontSize: '1rem', margin: '0', color: clayLight }}>Àmí by T</h1>
        <div style={{ display: 'flex', gap: '6px', marginTop: '10px' }}>
          <button style={{ flex: 1, padding: '7px', borderRadius: '4px', border: 'none', backgroundColor: softCream, color: '#000', fontWeight: 'bold', fontSize: '0.7rem' }}>Pickup</button>
          <button style={{ flex: 1, padding: '7px', borderRadius: '4px', border: `1px solid ${terracotta}`, backgroundColor: 'transparent', color: '#fff', fontSize: '0.7rem' }}>Delivery</button>
        </div>
      </div>

      {/* 4. COMPACT HORIZONTAL NAV */}
      <div style={{ display: 'flex', gap: '8px', overflowX: 'auto', padding: '10px 20px', scrollbarWidth: 'none' }}>
        {['Small Chops', 'Office Lunch', 'Wigs', 'About Us'].map((item) => (
          <button 
            key={item} 
            onClick={() => setActiveCategory(item)}
            style={{ 
              whiteSpace: 'nowrap', padding: '6px 14px', borderRadius: '4px', border: 'none',
              backgroundColor: activeCategory === item ? terracotta : '#111',
              color: activeCategory === item ? '#fff' : '#666',
              fontSize: '0.65rem', fontWeight: '700'
            }}
          >
            {item}
          </button>
        ))}
      </div>

      {/* 5. MAIN CONTENT - Gap removed */}
      <main style={{ paddingBottom: '60px', marginTop: '-15px' }}>
        <h3 style={{ padding: '0 20px 8px', fontSize: '0.85rem', color: clayLight }}>{activeCategory}</h3>
        <div style={{ transform: 'scale(0.97)', transformOrigin: 'top' }}>
          {activeCategory === 'Wigs' && <WigStore />}
          {activeCategory === 'Small Chops' && <Menu />}
          {activeCategory === 'Office Lunch' && <Lunch />}
        </div>
      </main>

    </div>
  );
}

export default App;
